inline uint32_t float_to_bits(float f) { uint32_t r; __builtin_memcpy(&r, &f, sizeof(r)); return r; }
#ifndef INFINITY
#define INFINITY __builtin_inff()
#endif
#define REDUCE_OP PoolType::SUM
#define REDUCE_DIM ReduceDim::REDUCE_COL
#include "api/compute/reduce.h"

void kernel_main() {
    // Compile-time CB indices (set by host runner compile_time_args = [0, 1]).
    const int32_t cb_game_dfb  = get_compile_time_arg_val(0);  // input  — game data
    const int32_t cb_out_dfb   = get_compile_time_arg_val(1);  // output — result text

    // num_tiles = 1: process one 32×32 tile per loop iteration (stub: one iteration).
    const int32_t num_tiles    = 1;
    // dst_tile_idx = 0: single tile slot in the destination register file.
    const size_t  dst_tile_idx = 0;

    // --- Wait for dm_reader to push a game tile into CB 0 ---
    cb_wait_front(cb_game_dfb, num_tiles);

    // --- Reserve space in CB 1 for the output tile ---
    cb_reserve_back(cb_out_dfb, num_tiles);

    // --- Copy tile from game_dfb to out_dfb (STUB: passthrough) ---
    // Full impl: replace with Z-machine interpret() + text output packing.
    init_sfpu(cb_game_dfb, cb_out_dfb);   // initialise SFPU for the CB pair
    tile_regs_acquire();                   // acquire exclusive access to tile register file
    copy_tile_init(cb_game_dfb);           // configure copy source = game_dfb
    copy_tile(cb_game_dfb, dst_tile_idx, dst_tile_idx);  // copy tile[0] → dst reg[0]
    tile_regs_commit();                    // release tile regs to packer
    tile_regs_wait();                      // wait for packer to acquire tile regs
    pack_tile<true>(dst_tile_idx, cb_out_dfb, dst_tile_idx);  // pack reg[0] → out_dfb
    tile_regs_release();                   // release tile regs back to unpacker

    // --- Push output tile to out_dfb, release consumed input ---
    cb_push_back(cb_out_dfb, num_tiles);   // signal dm_writer that out_dfb[0] is ready
    cb_pop_front(cb_game_dfb, num_tiles);  // release game_dfb[0] back to dm_reader

    return;
}
